def calculateMinimumHP(dungeon: list[list[int]]) -> int:
    R = len(dungeon)
    C = len(dungeon[0])

    dp = [[0] * C for _ in range(R)]

    dp[R-1][C-1] = max(1, 1 - dungeon[R-1][C-1])

    for c in range(C - 2, -1, -1):
        dp[R-1][c] = max(1, dp[R-1][c+1] - dungeon[R-1][c])

    for r in range(R - 2, -1, -1):
        dp[r][C-1] = max(1, dp[r+1][C-1] - dungeon[r][C-1])

    for r in range(R - 2, -1, -1):
        for c in range(C - 2, -1, -1):
            min_health_needed_at_next_cell = min(dp[r+1][c], dp[r][c+1])
            dp[r][c] = max(1, min_health_needed_at_next_cell - dungeon[r][c])

    return dp[0][0]
